const summary = $input.first().json;
const topItems = Array.isArray(summary.top_items) ? summary.top_items : [];
const lines = [
  'Internal reminders summary (local demo only)',
  `Total: ${summary.total_reminders ?? 0}`,
  `High: ${summary.high_count ?? 0}`,
  `Medium: ${summary.medium_count ?? 0}`,
  `Low: ${summary.low_count ?? 0}`,
  `Overdue: ${summary.overdue_count ?? 0}`,
  `Due today: ${summary.due_today_count ?? 0}`,
  `Due soon: ${summary.due_soon_count ?? 0}`,
  `Pending discovery review: ${summary.pending_review_count ?? 0}`,
  '',
  'Top items:'
];

if (topItems.length === 0) {
  lines.push('- No reminders returned.');
} else {
  for (const reminder of topItems) {
    lines.push(`- [${reminder.severity}] ${reminder.title}: ${reminder.description}`);
  }
}

return [
  {
    json: {
      formatted_message: lines.join('\n'),
      safe_output_only: true,
      no_external_notification_sent: true,
      source: 'http://backend:8000/reminders/n8n-summary'
    }
  }
];
